INSERT OR REPLACE INTO posts (id,slug,title,excerpt,body,category,tags,coverImage,sourceUrl,status,date,createdAt,updatedAt) VALUES
('post-pathway-workers','pathway-workers-programme-employs-over-17000','Pathway Workers Programme employs over 17,000','The Government''s National Pathway Workers Programme has employed 17,450 persons across Guyana as of 31 October 2025.','The Government''s National Pathway Workers Programme has employed a total of 17,450 persons across Guyana as of October 31, 2025. The programme continues to provide income support and community-based work opportunities in every region.

Through the Ministry of Local Government and Regional Development, the initiative places workers with local democratic organs to support cleaning, maintenance and community projects.','Programmes','["Programmes","Employment","Pathway Workers"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2026/06/WhatsApp-Image-2026-06-05-at-15.43.23.jpeg?w=1000&quality=82&ssl=1','https://dpi.gov.gy/pathway-workers-programme-employs-over-17000/','published','2026-06-09','2026-06-09T12:00:00.000Z','2026-06-09T12:00:00.000Z'),
('post-ret-programme','over-19000-guyanese-benefitted-from-ret-programme','Over 19,000 Guyanese benefitted from RET programme','More than 19,000 Guyanese have so far benefitted from the Government''s Regional Economic Transformation (RET) programme.','More than 19,000 Guyanese have so far benefitted from the Government''s Regional Economic Transformation (RET) programme. The programme supports community development and local economic activity across the regions.

The Ministry continues to work with Regional Democratic Councils to expand the reach of the programme and bring development closer to communities.','Programmes','["Programmes","RET","Economy"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2026/06/716799478_1463585782472714_4111538104565724208_n.jpg?w=1000&quality=82&ssl=1','https://dpi.gov.gy/over-19000-guyanese-benefitted-from-ret-programme/','published','2026-06-08','2026-06-08T12:00:00.000Z','2026-06-08T12:00:00.000Z'),
('post-region6-flooding','region-six-prepared-to-respond-to-potential-flooding-impacts','Region Six prepared to respond to potential flooding impacts','Regional Executive Officer of Region Six, Ronald Harsawack, says the region is ready to respond to potential flooding.','Regional Executive Officer (REO) of Region Six, Ronald Harsawack, has assured residents that the region is prepared to respond to potential flooding impacts. Drainage and irrigation systems are being monitored as part of ongoing readiness efforts.

The Ministry of Local Government and Regional Development continues to support the regions in disaster preparedness and response.','Regional Development','["Region 6","Flooding","Disaster Preparedness"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2026/06/716799478_1463585782472714_4111538104565724208_n.jpg?w=1000&quality=82&ssl=1','https://dpi.gov.gy/region-six-prepared-to-respond-to-potential-flooding-impacts/','published','2026-06-07','2026-06-07T12:00:00.000Z','2026-06-07T12:00:00.000Z'),
('post-lgc-legalities','government-to-upkeep-all-legalities-for-local-govt-commission','Government to uphold all legalities for the Local Government Commission','Minister Manickchand assured the National Assembly that all legal obligations under her ministry will be met.','Minister of Local Government and Regional Development, Hon. Priya Manickchand, MP, assured the National Assembly that all legal obligations falling under her ministry will be complied with, responding to questions regarding the Local Government Commission.

The Minister reaffirmed the Government''s commitment to the lawful and transparent administration of local government bodies.','Governance','["Governance","Local Government Commission","Minister"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2026/06/WhatsApp-Image-2026-06-05-at-15.43.22.jpeg?w=1000&quality=82&ssl=1','https://dpi.gov.gy/government-to-upkeep-all-legalities-for-local-govt-commission-min-manickchand/','published','2026-06-05','2026-06-05T12:00:00.000Z','2026-06-05T12:00:00.000Z'),
('post-anti-littering','govt-steps-up-anti-littering-efforts','Gov''t steps up anti-littering efforts to promote a cleaner Guyana','The Guyana Police Force and the Environmental Protection Agency are enforcing stricter measures against littering.','The Government has stepped up anti-littering efforts to promote a cleaner Guyana, with the Guyana Police Force and the Environmental Protection Agency enforcing stricter measures against littering.

The Ministry of Local Government and Regional Development is encouraging communities and councils to support a cleaner, healthier environment.','Environment','["Environment","Sanitation","Clean Guyana"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2026/06/10.jpeg?w=1000&quality=82&ssl=1','https://dpi.gov.gy/govt-steps-up-anti-littering-efforts-to-promote-a-cleaner-guyana/','published','2026-06-03','2026-06-03T12:00:00.000Z','2026-06-03T12:00:00.000Z'),
('post-region4-reo','new-region-four-reo-vows-people-centred-accountable-leadership','New Region Four REO vows people-centred, accountable leadership','The newly appointed Regional Executive Officer for Region Four pledged a people-centred, accountable administration.','The newly appointed Regional Executive Officer (REO) for Region Four has pledged a people-centred and accountable approach to regional administration, committing to improved service delivery and responsiveness to residents'' needs.

The appointment is part of a wider strengthening of leadership across the regions.','Local Democracy','["Region 4","REO","Appointments"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2026/05/704851274_122185917350891430_1144678879230800056_n-e1779660778741.jpg?w=1000&quality=82&ssl=1','https://dpi.gov.gy/new-region-four-reo-vows-people-centred-accountable-leadership/','published','2026-05-24','2026-05-24T12:00:00.000Z','2026-05-24T12:00:00.000Z'),
('post-region8-diversify','region-eight-residents-urged-to-diversify-economy','Region Eight residents urged to diversify economy through agriculture, tourism','Residents of Region Eight were urged to diversify their local economy through agriculture and tourism.','Residents of Region Eight have been urged to diversify their local economy through agriculture and tourism, highlighting opportunities to build sustainable livelihoods in the hinterland region.

The Ministry continues to support regional economic transformation across all ten administrative regions.','Regional Development','["Region 8","Agriculture","Tourism","Economy"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2026/05/WhatsApp-Image-2026-05-24-at-1.20.51-PM.jpeg?w=1000&quality=82&ssl=1','https://dpi.gov.gy/region-eight-residents-urged-to-diversify-economy-through-agriculture-tourism/','published','2026-05-24','2026-05-24T11:00:00.000Z','2026-05-24T11:00:00.000Z'),
('post-reo-rooplall','resolving-residents-everyday-concerns-is-paramount-reo-rooplall','Resolving residents'' everyday concerns is paramount – REO Rooplall','The newly appointed REO for Region Two, Deolall Rooplall, said resolving residents'' everyday concerns is paramount.','The newly appointed Regional Executive Officer (REO) for Region Two, Deolall Rooplall, said resolving residents'' everyday concerns is paramount, committing to a hands-on approach to local administration.

The Ministry of Local Government and Regional Development continues to engage regional officers to improve service delivery.','Local Democracy','["Region 2","REO","Service Delivery"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2026/05/WhatsApp-Image-2026-05-20-at-11.08.39.jpeg?w=1000&quality=82&ssl=1','https://dpi.gov.gy/resolving-residents-everyday-concerns-is-paramount-reo-rooplall/','published','2026-05-20','2026-05-20T12:00:00.000Z','2026-05-20T12:00:00.000Z'),
('post-reos-appointed','press-release-regional-executive-officers-appointed','Press Release: Regional Executive Officers appointed','The President of Guyana approved the appointment of new Regional Executive Officers across the administrative regions.','The President of Guyana has approved the appointment of new Regional Executive Officers (REOs) across the administrative regions. The appointments aim to strengthen regional administration and service delivery.

The Ministry of Local Government and Regional Development welcomes the new officers to their roles.','Press Release','["Appointments","REO","Press Release"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2026/05/5-e1779153337600.png?w=1000&quality=82&ssl=1','https://dpi.gov.gy/press-release-regional-executive-officers-appointed/','published','2026-05-17','2026-05-17T12:00:00.000Z','2026-05-17T12:00:00.000Z'),
('post-minister-assumes-office','min-manickchand-assumes-office','Minister Manickchand assumes office at the Ministry','Hon. Priya Manickchand officially assumed office as Minister of Local Government and Regional Development.','Hon. Priya Manickchand, MP, officially assumed office as Minister of Local Government and Regional Development. She was accompanied by Pauline Sukhai, who serves as Minister within the Ministry, and Director-General Anand Persaud.

Minister Manickchand was welcomed by the staff of the Ministry, who pledged their full support as the new leadership takes office, with a mandate to strengthen local governance and advance regional development.','Press Release','["Minister","Leadership","Press Release"]','https://i0.wp.com/dpi.gov.gy/wp-content/uploads/2025/09/547983471_1109632137997077_619129028257987321_n-1.jpg?w=1000&quality=82&ssl=1','https://dpi.gov.gy/min-manickchand-assumes-office-at-local-government-ministry/','published','2025-09-15','2025-09-15T12:00:00.000Z','2025-09-15T12:00:00.000Z');

